+      const badService = new NotificationService(eventBus);
+      // Register adapter that will fail for invalid email
+      badService.registerAdapter(badAdapter);
+
+      // Emit an order:created with an invalid email — the email adapter will fail
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser({ email: 'not-an-email' }),
+        timestamp: new Date(),
+      });
+
+      const logs = historyService.getLogs();
+      const failedLogs = logs.filter((l) => l.status === 'failed');
+      expect(failedLogs.length).toBeGreaterThanOrEqual(1);
+      expect(failedLogs[0]?.error).toBeDefined();
+    });
+  });
+
+  describe('querying by recipient', () => {
+    it('should return logs for a specific recipient', async () => {
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser({ email: 'alice@example.com' }),
+        timestamp: new Date(),
+      });
+
