+      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');
+
+      const bobLogs = historyService.getLogsByRecipient('bob@example.com');
+      expect(bobLogs).toHaveLength(1);
+
+      const noLogs = historyService.getLogsByRecipient('nobody@example.com');
+      expect(noLogs).toHaveLength(0);
+    });
+  });
+
+  describe('querying by type', () => {
