+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
+      });
+
+      await eventBus.emit({
+        type: 'order:status-changed',
+        order: makeOrder({ status: 'confirmed' }),
+        previousStatus: 'pending',
+        newStatus: 'confirmed',
+        timestamp: new Date(),
+      });
+
+      const confirmationLogs = historyService.getLogsByType('order_confirmation');
+      expect(confirmationLogs).toHaveLength(1);
+
+      const statusLogs = historyService.getLogsByType('order_status_update');
+      expect(statusLogs).toHaveLength(1);
+
+      const welcomeLogs = historyService.getLogsByType('user_welcome');
+      expect(welcomeLogs).toHaveLength(0);
+    });
