+      // so we use a range that includes the current time.
+      const now = new Date();
+      const pastStart = new Date(now.getTime() - 60_000);
+      const futureEnd = new Date(now.getTime() + 60_000);
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: now,
+      });
