+
+      const inRange = historyService.getLogsByDateRange(pastStart, futureEnd);
+      expect(inRange).toHaveLength(2);
+
+      const outOfRange = historyService.getLogsByDateRange(
+        new Date('2020-01-01'),
+        new Date('2020-12-31'),
+      );
+      expect(outOfRange).toHaveLength(0);
+    });
+  });
+
+  describe('querying by channel', () => {
+    it('should return logs for a specific channel', async () => {
+      await eventBus.emit({
+        type: 'order:created',
+        order: makeOrder(),
+        user: makeUser(),
+        timestamp: new Date(),
