/**
 * Notification log model for tracking sent notification history.
 *
 * Each log entry captures the details of a notification that was dispatched,
 * including its delivery status. Used by NotificationHistoryService for
 * querying historical notification data.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  status: DeliveryStatus;
  subject: string;
  body: string;
  error?: string;
  metadata?: Record<string, unknown>;
  timestamp: Date;
}

export interface NotificationLogQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, type, channel, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
import type { NotificationType } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as DeliveryStatus,
      subject: record['subject'] as string,
      body: record['body'] as string,
      error: record['error'] as string | undefined,
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
      timestamp: new Date(record['timestamp'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      subject: entity.subject,
      body: entity.body,
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
      timestamp: entity.timestamp.toISOString(),
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  query(params: NotificationLogQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (params.recipient && log.recipient !== params.recipient) return false;
      if (params.type && log.type !== params.type) return false;
      if (params.channel && log.channel !== params.channel) return false;
      if (params.status && log.status !== params.status) return false;
      if (params.startDate && log.timestamp < params.startDate) return false;
      if (params.endDate && log.timestamp > params.endDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs every dispatched notification and
 * provides query capabilities over the history.
 *
 * Architecture:
 * - Listens to notification:sent and notification:failed events on EventBus.
 * - Persists each notification as a NotificationLog entry via NotificationLogRepository.
 * - Provides query methods for filtering history by recipient, type, date range, etc.
 *
 * Depends on:
 * - EventBus for receiving notification lifecycle events
 * - NotificationLogRepository for persistence
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');
  private repository: NotificationLogRepository;

  constructor(eventBus: EventBus, repository: NotificationLogRepository) {
    this.repository = repository;
    this.registerHandlers(eventBus);
  }

  private registerHandlers(eventBus: EventBus): void {
    eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.logNotification(event.notification, 'sent', event.timestamp);
    });

    eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.logNotification(event.notification, 'failed', event.timestamp, event.error);
    });
  }

  private logNotification(
    notification: { id: string; type: NotificationType; channel: NotificationChannel; recipient: string; subject: string; body: string; metadata?: Record<string, unknown>; error?: string },
    status: DeliveryStatus,
    timestamp: Date,
    error?: string,
  ): void {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      status,
      subject: notification.subject,
      body: notification.body,
      error: error ?? notification.error,
      metadata: notification.metadata,
      timestamp,
    };

    this.repository.save(logEntry);
    this.logger.info(`Logged notification ${notification.id} with status ${status}`);
  }

  getLogs(): NotificationLog[] {
    return this.repository.findAll();
  }

  getLogsByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  getLogsByType(type: NotificationType): NotificationLog[] {
    return this.repository.findByType(type);
  }

  getLogsByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  getLogsByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.repository.findByStatus(status);
  }

  getLogsByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.query({ startDate, endDate });
  }

  query(params: NotificationLogQuery): NotificationLog[] {
    return this.repository.query(params);
  }

  getLogCount(): number {
    return this.repository.count();
  }
}

