function makeUser(overrides?: Partial<OrderCreatedEvent['user']>) {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
    ...overrides,
  };
}

function makeOrder(overrides?: Partial<OrderCreatedEvent['order']>) {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending' as const,
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
