}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let db: Database;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let emailAdapter: EmailAdapter;
  let logRepo: NotificationLogRepository;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    logRepo = new NotificationLogRepository(db);
    emailAdapter = new EmailAdapter();

    notificationService = new NotificationService(eventBus);
    notificationService.registerAdapter(emailAdapter);

    historyService = new NotificationHistoryService(eventBus, logRepo);

    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('logging sent notifications', () => {
    it('should log a notification when notification:sent is emitted', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date('2024-06-15T10:00:00Z'),
      };

      await eventBus.emit(event);

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.subject).toContain('Order Confirmation');
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder({ status: 'confirmed' }),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const logs = historyService.getLogs();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
    });

    it('should log failed notifications', async () => {
      const badAdapter = new EmailAdapter();
      const badService = new NotificationService(eventBus);
      // Register adapter that will fail for invalid email
      badService.registerAdapter(badAdapter);

      // Emit an order:created with an invalid email — the email adapter will fail
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser({ email: 'not-an-email' }),
        timestamp: new Date(),
      });

      const logs = historyService.getLogs();
      const failedLogs = logs.filter((l) => l.status === 'failed');
      expect(failedLogs.length).toBeGreaterThanOrEqual(1);
      expect(failedLogs[0]?.error).toBeDefined();
    });
  });

  describe('querying by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser({ email: 'alice@example.com' }),
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:created',
        order: makeOrder({ id: 'order-2', userId: 'user-2' }),
        user: makeUser({ id: 'user-2', email: 'bob@example.com' }),
        timestamp: new Date(),
      });

      const aliceLogs = historyService.getLogsByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getLogsByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);

      const noLogs = historyService.getLogsByRecipient('nobody@example.com');
      expect(noLogs).toHaveLength(0);
    });
  });

  describe('querying by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder({ status: 'confirmed' }),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const confirmationLogs = historyService.getLogsByType('order_confirmation');
      expect(confirmationLogs).toHaveLength(1);

      const statusLogs = historyService.getLogsByType('order_status_update');
      expect(statusLogs).toHaveLength(1);

      const welcomeLogs = historyService.getLogsByType('user_welcome');
      expect(welcomeLogs).toHaveLength(0);
    });
  });

  describe('querying by date range', () => {
    it('should return logs within a date range', async () => {
      const jan = new Date('2024-01-15T10:00:00Z');
      const mar = new Date('2024-03-15T10:00:00Z');

      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: jan,
      });

      await eventBus.emit({
        type: 'order:created',
        order: makeOrder({ id: 'order-2' }),
        user: makeUser(),
        timestamp: mar,
      });

      const janOnly = historyService.getLogsByDateRange(
        new Date('2024-01-01'),
        new Date('2024-02-01'),
      );
      expect(janOnly).toHaveLength(1);

      const all = historyService.getLogsByDateRange(
        new Date('2024-01-01'),
        new Date('2024-12-31'),
      );
      expect(all).toHaveLength(2);

      const none = historyService.getLogsByDateRange(
        new Date('2025-01-01'),
        new Date('2025-12-31'),
      );
      expect(none).toHaveLength(0);
    });
  });

  describe('querying by channel', () => {
    it('should return logs for a specific channel', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const emailLogs = historyService.getLogsByChannel('email');
      expect(emailLogs).toHaveLength(1);

      const webhookLogs = historyService.getLogsByChannel('webhook');
      expect(webhookLogs).toHaveLength(0);
    });
  });

  describe('querying by status', () => {
    it('should return logs for a specific status', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      const sentLogs = historyService.getLogsByStatus('sent');
      expect(sentLogs).toHaveLength(1);

      const failedLogs = historyService.getLogsByStatus('failed');
      expect(failedLogs).toHaveLength(0);
    });
  });

  describe('combined query', () => {
    it('should filter by multiple criteria', async () => {
      const ts = new Date('2024-06-15T10:00:00Z');

      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: ts,
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: makeOrder({ status: 'confirmed' }),
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: ts,
      });

      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        channel: 'email',
        status: 'sent',
        startDate: new Date('2024-01-01'),
        endDate: new Date('2024-12-31'),
      });

      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should return empty when no logs match', () => {
      const results = historyService.query({
        recipient: 'nobody@example.com',
      });
      expect(results).toHaveLength(0);
    });
  });

  describe('log count', () => {
    it('should return the count of logs', async () => {
      expect(historyService.getLogCount()).toBe(0);

      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(historyService.getLogCount()).toBe(1);
    });
  });

  describe('persistence via repository', () => {
    it('should persist logs in the database', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: makeOrder(),
        user: makeUser(),
        timestamp: new Date('2024-06-15T10:00:00Z'),
      });

      // Query directly from repository to confirm persistence
      const repoLogs = logRepo.findByRecipient('alice@example.com');
      expect(repoLogs).toHaveLength(1);
      expect(repoLogs[0]?.notificationId).toBe('notif-0001');
    });
  });
});

